32	/*! \file
33	    \brief A FP16 dense GEMM example for the NVIDIA Blackwell SM100 architecture using CUTLASS.
34	
35	    This example demonstrates minimal set of changes needed to transition from a Hopper CUTLASS 3.x 
36	    GEMM kernel (see example 48_hopper_warp_specialized_gemm) to a Blackwell 3.x CUTLASS GEMM kernel.
37	    
38	    The Blackwell SM100 CUTLASS kernel uses of the following Blackwell SM100 features:
39	
40	    1. New series of Tensor Core MMA Instructions (tcgen05) introduced on the Blackwell architecture (sm100a) 
41	    which have 2x throughput compared to Hopper Tensor Core MMA instructions (WGMMA). 
42	    
43	    Note that Hopper WGMMA Tensor Core MMA instructions are not compatible on Blackwell (See https://docs.nvidia.com/cuda/parallel-thread-execution). 
44	
45	    2. A new per-SM memory called Tensor Memory (TMEM) introduced on the Blackwell architecture (sm100a). 
46	    Blackwell SM100 Tensor Core MMA instructions store their accumulation results in TMEM instead of the 
47	    Register File. (Please refer to CUDA 12.8 docs on https://docs.nvidia.com/cuda/).
48	
49	    3. An extended flavor of the warp-specialized kernel design introduced in Hopper enabled by use of TMEM 
50	    which allows us to decouple the execution of MMA and epilogue into separate warps. 
51	
52	    4. A new SW controlled dynamic scheduler based on cluster launch control (See https://docs.nvidia.com/cuda/parallel-thread-execution). 
53	
54	    Usage:
55	      $ ./examples/70_blackwell_gemm/70_blackwell_fp16_gemm --m=8192 --n=8192 --k=8192
56	*/
57	
58	
59	
60	#include <iostream>
61	
62	#include "cutlass/cutlass.h"
63	
64	#include "cute/tensor.hpp"
65	#include "cutlass/tensor_ref.h"
66	#include "cutlass/epilogue/thread/linear_combination.h"
67	#include "cutlass/gemm/dispatch_policy.hpp"
68	#include "cutlass/gemm/collective/collective_builder.hpp"
69	#include "cutlass/epilogue/collective/collective_builder.hpp"
70	#include "cutlass/gemm/device/gemm_universal_adapter.h"
71	#include "cutlass/gemm/kernel/gemm_universal.hpp"
72	#include "cutlass/gemm/kernel/tile_scheduler_params.h"
73	
74	#include "cutlass/util/command_line.h"
75	#include "cutlass/util/distribution.h"
76	#include "cutlass/util/host_tensor.h"
77	#include "cutlass/util/packed_stride.hpp"
78	#include "cutlass/util/tensor_view_io.h"
79	#include "cutlass/util/reference/device/gemm.h"
80	#include "cutlass/util/reference/device/tensor_compare.h"
81	#include "cutlass/util/reference/device/tensor_fill.h"
82	
83	#include "helper.h"
84	
85	using namespace cute;
86	
87	#if defined(CUTLASS_ARCH_MMA_SM100_SUPPORTED)
88	
89	/////////////////////////////////////////////////////////////////////////////////////////////////
90	/// GEMM kernel configurations
91	/////////////////////////////////////////////////////////////////////////////////////////////////
92	
93	// A matrix configuration
94	using         ElementA    = half_t;                                         // Element type for A matrix operand
95	using         LayoutA     = cutlass::layout::RowMajor;                      // Layout type for A matrix operand
96	constexpr int AlignmentA  = 128 / cutlass::sizeof_bits<ElementA>::value;    // Memory access granularity/alignment of A matrix in units of elements (up to 16 bytes)
97	
98	// B matrix configuration
99	using         ElementB    = half_t;                                         // Element type for B matrix operand
100	using         LayoutB     = cutlass::layout::ColumnMajor;                   // Layout type for B matrix operand
101	constexpr int AlignmentB  = 128 / cutlass::sizeof_bits<ElementB>::value;    // Memory access granularity/alignment of B matrix in units of elements (up to 16 bytes)
102	
103	// C/D matrix configuration
104	using         ElementC    = float;                                          // Element type for C and D matrix operands
105	using         LayoutC     = cutlass::layout::ColumnMajor;                   // Layout type for C and D matrix operands
106	constexpr int AlignmentC  = 128 / cutlass::sizeof_bits<ElementC>::value;    // Memory access granularity/alignment of C matrix in units of elements (up to 16 bytes)
107	
108	// Kernel functional config
109	using ElementAccumulator  = float;                                          // Element type for internal accumulation
110	using ArchTag             = cutlass::arch::Sm100;                           // Tag indicating the minimum SM that supports the intended feature
111	using OperatorClass       = cutlass::arch::OpClassTensorOp;                 // Operator class tag
112	
113	// MMA and Cluster Tile Shapes
114	// Shape of the tile computed by tcgen05 MMA, could be across 2 SMs if Cluster Shape %2 == 0 
115	using MmaTileShape_MNK = Shape<_256,_128,_64>;                          
116	// Shape of the threadblocks in a cluster
117	using ClusterShape_MNK = Shape<_2,_2,_1>;
118	
119	// Build the epilogue
120	using CollectiveEpilogue = typename cutlass::epilogue::collective::CollectiveBuilder<
121	    ArchTag, OperatorClass, 
122	    MmaTileShape_MNK, ClusterShape_MNK,
123	    cutlass::epilogue::collective::EpilogueTileAuto,
124	    ElementAccumulator, ElementAccumulator,
125	    ElementC, LayoutC, AlignmentC,
126	    ElementC, LayoutC, AlignmentC,
127	    cutlass::epilogue::collective::EpilogueScheduleAuto
128	  >::CollectiveOp;
129	
130	// Build the mainloop
131	using CollectiveMainloop = typename cutlass::gemm::collective::CollectiveBuilder<
132	    ArchTag, OperatorClass,
133	    ElementA, LayoutA, AlignmentA,
134	    ElementB, LayoutB, AlignmentB,
135	    ElementAccumulator,
136	    MmaTileShape_MNK, ClusterShape_MNK,
137	    cutlass::gemm::collective::StageCountAutoCarveout<static_cast<int>(sizeof(typename CollectiveEpilogue::SharedStorage))>,
138	    cutlass::gemm::collective::KernelScheduleAuto
139	  >::CollectiveOp;
140	
141	// Compose into a kernel
142	using GemmKernel = cutlass::gemm::kernel::GemmUniversal<
143	    Shape<int,int,int, int>, // Indicates ProblemShape
144	    CollectiveMainloop,
145	    CollectiveEpilogue,
146	    void>;                   // Default to ClusterLaunchControl (CLC) based tile scheduler 
147	
148	using Gemm = cutlass::gemm::device::GemmUniversalAdapter<GemmKernel>;
149	
150	// Reference device GEMM implementation type
151	using DeviceGemmReference = cutlass::reference::device::Gemm<
152	  ElementA,
153	  LayoutA,
154	  ElementB,
155	  LayoutB,
156	  ElementC,
157	  LayoutC,
158	  ElementAccumulator,
159	  ElementAccumulator>;
160	
161	using StrideA = typename Gemm::GemmKernel::StrideA;
162	using StrideB = typename Gemm::GemmKernel::StrideB;
163	using StrideC = typename Gemm::GemmKernel::StrideC;
164	using StrideD = typename Gemm::GemmKernel::StrideD;
165	
166	//
167	// Data members
168	//
169	
170	/// Initialization
171	StrideA stride_A;
172	StrideB stride_B;
173	StrideC stride_C;
174	StrideD stride_D;
175	uint64_t seed;
176	
177	cutlass::DeviceAllocation<typename Gemm::ElementA> block_A;
178	cutlass::DeviceAllocation<typename Gemm::ElementB> block_B;
179	cutlass::DeviceAllocation<typename Gemm::ElementC> block_C;
180	cutlass::DeviceAllocation<typename Gemm::EpilogueOutputOp::ElementOutput> block_D;
181	cutlass::DeviceAllocation<typename Gemm::EpilogueOutputOp::ElementOutput> block_ref_D;
182	
183	#endif // defined(CUTLASS_ARCH_MMA_SM100_SUPPORTED)
184	
185	/////////////////////////////////////////////////////////////////////////////////////////////////
186	/// Testbed utility types
187	/////////////////////////////////////////////////////////////////////////////////////////////////
188	
189	// Command line options parsing
190	struct Options {
191	
192	  bool help;
193	
194	  float alpha, beta;
195	  int iterations;
196	  int m, n, k;
197	  int swizzle;
198	
199	  Options():
200	    help(false),
201	    m(8192), n(8192), k(8192),
202	    alpha(1.f), beta(0.f),
203	    iterations(10),
204	    swizzle(0)
205	  { }
206	
207	  // Parses the command line
208	  void parse(int argc, char const **args) {
209	    cutlass::CommandLine cmd(argc, args);
210	
211	    if (cmd.check_cmd_line_flag("help")) {
212	      help = true;
213	      return;
214	    }
215	
216	    cmd.get_cmd_line_argument("m", m);
217	    cmd.get_cmd_line_argument("n", n);
218	    cmd.get_cmd_line_argument("k", k);
219	    cmd.get_cmd_line_argument("alpha", alpha, 1.f);
220	    cmd.get_cmd_line_argument("beta", beta, 0.f);
221	    cmd.get_cmd_line_argument("iterations", iterations);
222	    cmd.get_cmd_line_argument("swizzle", swizzle);
223	  }
224	
225	  /// Prints the usage statement.
226	  std::ostream & print_usage(std::ostream &out) const {
227	
228	    out << "70_blackwell_fp16_gemm\n\n"
229	      << "  Blackwell FP16 GEMM using a Warp Specialized kernel.\n\n"
230	      << "Options:\n\n"
231	      << "  --help                      If specified, displays this usage statement\n\n"
232	      << "  --m=<int>                   Sets the M extent of the GEMM\n"
233	      << "  --n=<int>                   Sets the N extent of the GEMM\n"
234	      << "  --k=<int>                   Sets the K extent of the GEMM\n"
235	      << "  --alpha=<f32>               Epilogue scalar alpha\n"
236	      << "  --beta=<f32>                Epilogue scalar beta\n\n"
237	      << "  --swizzle=<int>             Cluster rasterization swizzle\n\n"
238	      << "  --iterations=<int>          Number of profiling iterations to perform.\n\n";
239	
240	    out
241	      << "\n\nExamples:\n\n"
242	      << "$ " << "70_blackwell_fp16_gemm" << " --m=1024 --n=512 --k=1024 --alpha=2 --beta=0.707 \n\n";
243	
244	    return out;
245	  }
246	
247	  /// Compute performance in GFLOP/s
248	  double gflops(double runtime_s) const
249	  {
250	    // Two flops per multiply-add
251	    uint64_t flop = uint64_t(2) * m * n * k;
252	    double gflop = double(flop) / double(1.0e9);
253	    return gflop / runtime_s;
254	  }
255	};
256	
257	/// Result structure
258	struct Result
259	{
260	  double avg_runtime_ms;
261	  double gflops;
262	  cutlass::Status status;
263	  cudaError_t error;
264	  bool passed;
265	
266	  Result(
267	    double avg_runtime_ms = 0,
268	    double gflops = 0,
269	    cutlass::Status status = cutlass::Status::kSuccess,
270	    cudaError_t error = cudaSuccess)
271	  :
272	    avg_runtime_ms(avg_runtime_ms), gflops(gflops), status(status), error(error), passed(false)
273	  {}
274	
275	};
276	
277	#if defined(CUTLASS_ARCH_MMA_SM100_SUPPORTED)
278	
279	/////////////////////////////////////////////////////////////////////////////////////////////////
280	/// GEMM setup and evaluation
281	/////////////////////////////////////////////////////////////////////////////////////////////////
282	
283	/// Helper to initialize a block of device data
284	template <class Element>
285	bool initialize_block(
286	  cutlass::DeviceAllocation<Element>& block,
287	  uint64_t seed=2023) {
288	
289	  Element scope_max, scope_min;
290	  int bits_input = cutlass::sizeof_bits<Element>::value;
291	
292	  if (bits_input == 1) {
293	    scope_max = Element(2);
294	    scope_min = Element(0);
295	  } else if (bits_input <= 8) {
296	    scope_max = Element(2);
297	    scope_min = Element(-2);
298	  } else {
299	    scope_max = Element(8);
300	    scope_min = Element(-8);
301	  }
302	
303	  cutlass::reference::device::BlockFillRandomUniform(
304	    block.get(), block.size(), seed, scope_max, scope_min, 0);
305	
306	  return true;
307	}
308	
309	/// Initialize operands to be used in the GEMM and reference GEMM
310	void initialize(const Options &options) {
311	
312	  stride_A = cutlass::make_cute_packed_stride(StrideA{}, {options.m, options.k, 1});
313	  stride_B = cutlass::make_cute_packed_stride(StrideB{}, {options.n, options.k, 1});
314	  stride_C = cutlass::make_cute_packed_stride(StrideC{}, {options.m, options.n, 1});
315	  stride_D = cutlass::make_cute_packed_stride(StrideD{}, {options.m, options.n, 1});
316	
317	  block_A.reset(options.m * options.k);
318	  block_B.reset(options.k * options.n);
319	  block_C.reset(options.m * options.n);
320	  block_D.reset(options.m * options.n);
321	  block_ref_D.reset(options.m * options.n);
322	
323	  initialize_block(block_A, seed + 2023);
324	  initialize_block(block_B, seed + 2022);
325	  initialize_block(block_C, seed + 2021);
326	}
327	
328	/// Populates a Gemm::Arguments structure from the given commandline options
329	typename Gemm::Arguments args_from_options(const Options &options)
330	{
331	  typename Gemm::Arguments arguments{
332	    cutlass::gemm::GemmUniversalMode::kGemm,
333	    {options.m, options.n, options.k, 1},
334	    {block_A.get(), stride_A, block_B.get(), stride_B},
335	    {{options.alpha, options.beta}, block_C.get(), stride_C, block_D.get(), stride_D}
336	  };
337	
338	  arguments.scheduler.max_swizzle_size = options.swizzle;
339	
340	  return arguments;
341	}
342	
343	bool verify(const Options &options) {
344	  cutlass::TensorRef ref_A(block_A.get(), Gemm::LayoutA::packed({options.m, options.k}));
345	  cutlass::TensorRef ref_B(block_B.get(), Gemm::LayoutB::packed({options.k, options.n}));
346	  cutlass::TensorRef ref_C(block_C.get(), Gemm::LayoutC::packed({options.m, options.n}));
347	  cutlass::TensorRef ref_D(block_ref_D.get(), Gemm::LayoutD::packed({options.m, options.n}));
348	
349	  //
350	  // Compute reference output
351	  //
352	
353	  // Create instantiation for device reference gemm kernel
354	  DeviceGemmReference gemm_reference;
355	
356	  // Launch device reference gemm kernel
357	  gemm_reference(
358	    {options.m, options.n, options.k},
359	    ElementAccumulator(options.alpha),
360	    ref_A,
361	    ref_B,
362	    ElementAccumulator(options.beta),
363	    ref_C,
364	    ref_D);
365	
366	  // Wait for kernel to finish
367	  CUDA_CHECK(cudaDeviceSynchronize());
368	
369	  // Check if output from CUTLASS kernel and reference kernel are equal or not
370	  bool passed = cutlass::reference::device::BlockCompareEqual(block_ref_D.get(), block_D.get(), block_D.size());
371	
372	  return passed;
373	}
374	
375	/// Execute a given example GEMM computation
376	template <typename Gemm>
377	int run(Options &options)
378	{
379	  initialize(options);
380	
381	  // Instantiate CUTLASS kernel depending on templates
382	  Gemm gemm;
383	
384	  // Create a structure of gemm kernel arguments suitable for invoking an instance of Gemm
385	  auto arguments = args_from_options(options);
386	
387	  // Using the arguments, query for extra workspace required for matrix multiplication computation
388	  size_t workspace_size = Gemm::get_workspace_size(arguments);
389	
390	  // Allocate workspace memory
391	  cutlass::device_memory::allocation<uint8_t> workspace(workspace_size);
392	
393	  // Check if the problem size is supported or not
394	  CUTLASS_CHECK(gemm.can_implement(arguments));
395	
396	  // Initialize CUTLASS kernel with arguments and workspace pointer
397	  CUTLASS_CHECK(gemm.initialize(arguments, workspace.get()));
398	
399	  // Correctness / Warmup iteration
400	  CUTLASS_CHECK(gemm.run());
401	
402	  // Check if output from CUTLASS kernel and reference kernel are equal or not
403	  Result result;
404	  result.passed = verify(options);
405	
406	  std::cout << "  Disposition: " << (result.passed ? "Passed" : "Failed") << std::endl;
407	
408	  if (!result.passed) {
409	    exit(-1);
410	  }
411	
412	  // Run profiling loop
413	  if (options.iterations > 0)
414	  {
415	    GpuTimer timer;
416	    timer.start();
417	    for (int iter = 0; iter < options.iterations; ++iter) {
418	      CUTLASS_CHECK(gemm.initialize(arguments, workspace.get()));
419	      CUTLASS_CHECK(gemm.run());
420	    }
421	    timer.stop();
422	
423	    // Compute average runtime and GFLOPs.
424	    float elapsed_ms = timer.elapsed_millis();
425	    result.avg_runtime_ms = double(elapsed_ms) / double(options.iterations);
426	    result.gflops = options.gflops(result.avg_runtime_ms / 1000.0);
427	
428	
429	    std::cout << "  Problem Size: " << options.m << 'x' << options.n << 'x' << options.k << std::endl;
430	    std::cout << "  Avg runtime: " << result.avg_runtime_ms << " ms" << std::endl;
431	    std::cout << "  GFLOPS: " << result.gflops << std::endl;
432	  }
433	
434	  return 0;
435	}
436	
437	#endif // defined(CUTLASS_ARCH_MMA_SM100_SUPPORTED)
438	
439	///////////////////////////////////////////////////////////////////////////////////////////////////
440	
441	int main(int argc, char const **args) {
442	
443	  // CUTLASS must be compiled with CUDA 12.8 Toolkit to run this example
444	  // and must have compute capability at least 100a.
445	
446	  if (__CUDACC_VER_MAJOR__ < 12 || (__CUDACC_VER_MAJOR__ == 12 && __CUDACC_VER_MINOR__ < 8)) {
447	    std::cerr << "This example requires CUDA 12.8 or newer." << std::endl;
448	    // Returning zero so this test passes on older Toolkits. Its actions are no-op.
449	    return 0;
450	  }
451	
452	  cudaDeviceProp props;
453	  int current_device_id;
454	  CUDA_CHECK(cudaGetDevice(&current_device_id));
455	  CUDA_CHECK(cudaGetDeviceProperties(&props, current_device_id));  
456	  cudaError_t error = cudaGetDeviceProperties(&props, 0);
457	
458	  if (props.major != 10 || props.minor != 0) {
459	    std::cerr << "This example requires a GPU with compute capability 100a)." << std::endl;
460	    return 0;
461	  }
462	
463	  //
464	  // Parse options
465	  //
466	
467	  Options options;
468	
469	  options.parse(argc, args);
470	
471	  if (options.help) {
472	    options.print_usage(std::cout) << std::endl;
473	    return 0;
474	  }
475	
476	  //
477	  // Evaluate CUTLASS kernels
478	  //
479	#if defined(CUTLASS_ARCH_MMA_SM100_SUPPORTED)
480	  run<Gemm>(options);
481	#endif // defined(CUTLASS_ARCH_MMA_SM100_SUPPORTED)
482	
483	  return 0;
484	}
485	
486	/////////////////////////////////////////////////////////////////////////////////////////////////
487

